602	    fn stringNeedsQuotes(str: String) bool {
603	        if (str.isEmpty()) {
604	            return true;
605	        }
606	
607	        switch (str.charAt(str.length() - 1)) {
608	            // whitespace characters
609	            ' ',
610	            '\t',
611	            '\n',
612	            '\r',
613	            // trailing colon can be misinterpreted as a mapping indicator
614	            // https://github.com/oven-sh/bun/issues/25439
615	            ':',
616	            => return true,
617	            else => {},
618	        }
619	
620	        switch (str.charAt(0)) {
621	            // starting with an indicator character requires quotes
622	            '&',
623	            '*',
624	            '?',
625	            '|',
626	            '-',
627	            '<',
628	            '>',
629	            '!',
630	            '%',
631	            '@',
632	            ':',
633	            ',',
634	            '[',
635	            ']',
636	            '{',
637	            '}',
638	            '#',
639	            '\'',
640	            '"',
641	            '`',
642	            // starting with whitespace requires quotes
643	            ' ',
644	            '\t',
645	            '\n',
646	            '\r',
647	            => return true,
648	
649	            else => {},
650	        }
651	
652	        const keywords = &.{
653	            "true",
654	            "True",
655	            "TRUE",
656	            "false",
657	            "False",
658	            "FALSE",
659	            "yes",
660	            "Yes",
661	            "YES",
662	            "no",
663	            "No",
664	            "NO",
665	            "on",
666	            "On",
667	            "ON",
668	            "off",
669	            "Off",
670	            "OFF",
671	            "n",
672	            "N",
673	            "y",
674	            "Y",
675	            "null",
676	            "Null",
677	            "NULL",
678	            "~",
679	            ".inf",
680	            ".Inf",
681	            ".INF",
682	            ".nan",
683	            ".NaN",
684	            ".NAN",
685	        };
686	
687	        inline for (keywords) |keyword| {
688	            if (str.eqlComptime(keyword)) {
689	                return true;
690	            }
691	        }
692	
693	        var i: usize = 0;
694	        while (i < str.length()) {
695	            switch (str.charAt(i)) {
696	                // flow indicators need to be quoted always
697	                '{',
698	                '}',
699	                '[',
700	                ']',
701	                ',',
702	                => return true,
703	
704	                ':',
705	                => {
706	                    if (i + 1 < str.length()) {
707	                        switch (str.charAt(i + 1)) {
708	                            ' ',
709	                            '\t',
710	                            '\n',
711	                            '\r',
712	                            => return true,
713	                            else => {},
714	                        }
715	                    }
716	                    i += 1;
717	                },
718	
719	                '#',
720	                '`',
721	                '\'',
722	                => return true,
723	
724	                '-' => {
725	                    if (i + 2 < str.length() and str.charAt(i + 1) == '-' and str.charAt(i + 2) == '-') {
726	                        if (i + 3 >= str.length()) {
727	                            return true;
728	                        }
729	                        switch (str.charAt(i + 3)) {
730	                            ' ',
731	                            '\t',
732	                            '\r',
733	                            '\n',
734	                            '[',
735	                            ']',
736	                            '{',
737	                            '}',
738	                            ',',
739	                            => return true,
740	                            else => {},
741	                        }
742	                    }
743	
744	                    if (i == 0 and stringIsNumber(str, &i)) {
745	                        return true;
746	                    }
747	                    i += 1;
748	                },
749	                '.' => {
750	                    if (i + 2 < str.length() and str.charAt(i + 1) == '.' and str.charAt(i + 2) == '.') {
751	                        if (i + 3 >= str.length()) {
752	                            return true;
753	                        }
754	                        switch (str.charAt(i + 3)) {
755	                            ' ',
756	                            '\t',
757	                            '\r',
758	                            '\n',
759	                            '[',
760	                            ']',
761	                            '{',
762	                            '}',
763	                            ',',
764	                            => return true,
765	                            else => {},
