// Bun.INI — INI format parser and stringifier
//
// Supports:
//  - Comment lines: `;...` and `#...` (after optional whitespace)
//  - Sections: `[name]` — represented as nested objects
//  - Key-value pairs: `key = value` or `key: value` (whitespace is trimmed)
//  - Inline comments: `key = value ; comment` (stripped outside of quotes)
//  - Quoted values: `key = "value"` or `key = 'value'`
//
// All values are returned as strings.

pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
    const object = JSValue.createEmptyObject(globalThis, 2);
    object.put(
        globalThis,
        ZigString.static("parse"),
        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}),
    );
    object.put(
        globalThis,
        ZigString.static("stringify"),
        jsc.JSFunction.create(globalThis, "stringify", stringify, 1, .{}),
    );
    return object;
}

