      const result = Bun.INI.parse(input);
      expect(result.version).toBe("1.0");
      expect(result.debug).toBe("true");
      expect((result as any).app).toEqual({ name: "MyApp" });
    });

    test("ignores semicolon comment lines", () => {
      const input = `; This is a comment
key = value`;
      expect(Bun.INI.parse(input)).toEqual({ key: "value" });
    });

    test("ignores hash comment lines", () => {
      const input = `# This is a comment
key = value`;
      expect(Bun.INI.parse(input)).toEqual({ key: "value" });
    });

    test("strips inline semicolon comments", () => {
      const result = Bun.INI.parse("key = value ; inline comment");
      expect(result).toEqual({ key: "value" });
    });

    test("strips inline hash comments", () => {
      const result = Bun.INI.parse("key = value # inline comment");
      expect(result).toEqual({ key: "value" });
    });

    test("does not strip inline comments inside double-quoted values", () => {
      const result = Bun.INI.parse(`key = "value ; with semicolon"`);
      expect(result).toEqual({ key: "value ; with semicolon" });
    });

    test("does not strip inline comments inside single-quoted values", () => {
      const result = Bun.INI.parse(`key = 'value # with hash'`);
      expect(result).toEqual({ key: "value # with hash" });
    });

    test("trims whitespace around keys and values", () => {
      const result = Bun.INI.parse("  key  =  value  ");
      expect(result).toEqual({ key: "value" });
    });

    test("unquotes double-quoted values", () => {
      const result = Bun.INI.parse(`key = "hello world"`);
      expect(result).toEqual({ key: "hello world" });
    });

    test("unquotes single-quoted values", () => {
      const result = Bun.INI.parse(`key = 'hello world'`);
      expect(result).toEqual({ key: "hello world" });
    });

    test("handles empty values", () => {
      const result = Bun.INI.parse("key =");
      expect(result).toEqual({ key: "" });
    });

    test("handles empty input", () => {
      const result = Bun.INI.parse("");
      expect(result).toEqual({});
    });

    test("handles only comments", () => {
      const result = Bun.INI.parse("; just a comment\n# another comment");
      expect(result).toEqual({});
    });

    test("handles Windows-style CRLF line endings", () => {
      const result = Bun.INI.parse("key = value\r\nother = 42");
      expect(result).toEqual({ key: "value", other: "42" });
    });

    test("handles section header with whitespace around name", () => {
      const result = Bun.INI.parse("[ section ]\nkey = val");
      expect(result).toEqual({ section: { key: "val" } });
    });

    test("throws on non-string input", () => {
      expect(() => Bun.INI.parse(null as any)).toThrow();
    });
  });

  describe("stringify", () => {
    test("stringifies simple key=value object", () => {
      const result = Bun.INI.stringify({ name: "Alice", age: 30 });
      expect(result).toContain("name = Alice");
      expect(result).toContain("age = 30");
    });

    test("stringifies sections from nested objects", () => {
      const obj = {
        database: { host: "localhost", port: 5432 },
      };
      const result = Bun.INI.stringify(obj);
      expect(result).toContain("[database]");
      expect(result).toContain("host = localhost");
      expect(result).toContain("port = 5432");
    });

    test("writes scalar properties before sections", () => {
      const obj = {
        version: "1.0",
        app: { name: "MyApp" },
      };
      const result = Bun.INI.stringify(obj);
      const versionPos = result.indexOf("version = 1.0");
      const sectionPos = result.indexOf("[app]");
      expect(versionPos).toBeGreaterThanOrEqual(0);
      expect(sectionPos).toBeGreaterThan(versionPos);
    });

    test("stringifies boolean values", () => {
      const result = Bun.INI.stringify({ enabled: true, disabled: false });
      expect(result).toContain("enabled = true");
      expect(result).toContain("disabled = false");
    });

    test("stringifies number values", () => {
      const result = Bun.INI.stringify({ count: 42, ratio: 3.14 });
      expect(result).toContain("count = 42");
      expect(result).toContain("ratio = 3.14");
    });

    test("stringifies null values", () => {
      const result = Bun.INI.stringify({ value: null });
      expect(result).toContain("value = null");
    });

    test("stringifies array values as comma-separated", () => {
      const result = Bun.INI.stringify({ tags: ["a", "b", "c"] });
      expect(result).toContain("tags = a, b, c");
    });

    test("quotes values containing comment characters", () => {
      const result = Bun.INI.stringify({ note: "hello ; world" });
      expect(result).toContain('"hello ; world"');
    });

    test("quotes values containing newlines", () => {
      const result = Bun.INI.stringify({ text: "line1\nline2" });
      expect(result).toContain('"line1\\nline2"');
    });

    test("quotes values with leading whitespace", () => {
      const result = Bun.INI.stringify({ padded: " indented" });
      expect(result).toContain('" indented"');
    });

    test("produces output parseable by Bun.INI.parse", () => {
      const original = {
        host: "localhost",
        port: "8080",
        database: {
          name: "mydb",
          user: "admin",
        },
      };
      const ini = Bun.INI.stringify(original);
      const parsed = Bun.INI.parse(ini);
      expect(parsed.host).toBe("localhost");
      expect(parsed.port).toBe("8080");
      expect((parsed as any).database.name).toBe("mydb");
      expect((parsed as any).database.user).toBe("admin");
    });

    test("round-trips a realistic config", () => {
      const config = Bun.INI.parse(`
; Application configuration
version = 2.1

[server]
host = 127.0.0.1
port = 3000
debug = false

[database]
; Primary DB
host = db.example.com
port = 5432
name = production
`);
      const stringified = Bun.INI.stringify(config);
      const reparsed = Bun.INI.parse(stringified);
      expect(reparsed).toEqual(config);
    });

    test("throws on non-object input", () => {
      expect(() => Bun.INI.stringify("not an object" as any)).toThrow();
      expect(() => Bun.INI.stringify(null as any)).toThrow();
    });

    test("skips undefined, symbol, and function properties", () => {
      const obj = {
        keep: "yes",
        skip_undef: undefined,
        skip_fn: () => {},
      };
      const result = Bun.INI.stringify(obj as any);
      expect(result).toContain("keep = yes");
      expect(result).not.toContain("skip_undef");
      expect(result).not.toContain("skip_fn");
    });
  });
});

