117	/// Stringify a JavaScript object into INI format.
118	/// Top-level scalar properties become bare `key = value` lines.
119	/// Top-level object properties become INI sections: `[name]\nkey = value\n...`
120	/// Arrays are serialized as comma-separated values.
121	pub fn stringify(global: *jsc.JSGlobalObject, callFrame: *jsc.CallFrame) bun.JSError!jsc.JSValue {
122	    const value = callFrame.argument(0);
123	
124	    if (value.isEmptyOrUndefinedOrNull() or !value.isObject()) {
125	        return global.throwInvalidArguments("Expected an object to stringify", .{});
126	    }
