131	    var anything_written = false;
132	
133	    // First pass: write top-level scalar (non-section) properties
134	    {
135	        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
136	            global,
137	            try value.toObject(global),
138	        );
139	        defer iter.deinit();
140	
141	        while (try iter.next()) |prop_name| {
142	            const prop_value = iter.value;
143	            if (prop_value.isUndefined() or prop_value.isSymbol() or prop_value.isFunction()) continue;
144	            // Skip plain objects — they become sections in the second pass
145	            if (prop_value.isObject() and !prop_value.isArray()) continue;
146	
147	            builder.append(.string, prop_name);
148	            builder.append(.latin1, " = ");
149	            try appendINIValue(&builder, global, prop_value);
