155	    // Second pass: write top-level object properties as INI sections
156	    {
157	        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
158	            global,
159	            try value.toObject(global),
160	        );
161	        defer iter.deinit();
162	
163	        while (try iter.next()) |prop_name| {
