166	            if (!prop_value.isObject() or prop_value.isArray()) continue;
167	
168	            // Blank line before each section when something precedes it
169	            if (anything_written) builder.append(.lchar, '\n');
170	
171	            builder.append(.lchar, '[');
172	            builder.append(.string, prop_name);
173	            builder.append(.latin1, "]\n");
174	
175	            var sec_iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
176	                global,
177	                try prop_value.toObject(global),
178	            );
