198	fn appendINIValue(builder: *wtf.StringBuilder, global: *jsc.JSGlobalObject, value: JSValue) bun.JSError!void {
199	    const unwrapped = try value.unwrapBoxedPrimitive(global);
200	
201	    if (unwrapped.isNull()) {
202	        builder.append(.latin1, "null");
203	        return;
204	    }
205	
206	    if (unwrapped.isBoolean()) {
207	        builder.append(.latin1, if (unwrapped.asBoolean()) "true" else "false");
208	        return;
209	    }
210	
211	    if (unwrapped.isInt32()) {
212	        builder.append(.int, unwrapped.asInt32());
213	        return;
214	    }
215	
216	    if (unwrapped.isNumber()) {
217	        builder.append(.double, unwrapped.asNumber());
218	        return;
219	    }
220	
221	    if (unwrapped.isArray()) {
222	        // Serialize arrays as comma-separated values
223	        var iter = try unwrapped.arrayIterator(global);
224	        var first = true;
225	        while (try iter.next()) |item| {
226	            if (!first) builder.append(.latin1, ", ");
227	            first = false;
228	            if (item.isNull() or item.isUndefined()) {
229	                // write nothing for null/undefined array elements
230	            } else if (item.isBoolean()) {
231	                builder.append(.latin1, if (item.asBoolean()) "true" else "false");
232	            } else if (item.isInt32()) {
233	                builder.append(.int, item.asInt32());
234	            } else if (item.isNumber()) {
235	                builder.append(.double, item.asNumber());
236	            } else {
237	                const item_str = try item.toBunString(global);
238	                defer item_str.deref();
239	                appendINIStringValue(builder, item_str);
240	            }
241	        }
242	        return;
243	    }
244	
245	    if (unwrapped.isString()) {
246	        const str = try unwrapped.toBunString(global);
247	        defer str.deref();
248	        appendINIStringValue(builder, str);
249	        return;
250	    }
251	
252	    // Fallback: convert to string representation
253	    const str = try unwrapped.toBunString(global);
254	    defer str.deref();
255	    appendINIStringValue(builder, str);
256	}
