258	/// Write an INI string value, quoting it if it contains characters that
259	/// would be misinterpreted (comment markers, newlines, leading/trailing whitespace).
260	fn appendINIStringValue(builder: *wtf.StringBuilder, str: bun.String) void {
261	    const needs_quotes = needs_quotes: {
262	        if (str.length() == 0) break :needs_quotes false;
263	        const first = str.charAt(0);
264	        const last = str.charAt(str.length() - 1);
265	        // Leading or trailing whitespace must be quoted to survive a round-trip
266	        if (first == ' ' or first == '\t' or last == ' ' or last == '\t') break :needs_quotes true;
267	        // Inline-comment markers and newlines require quoting
268	        for (0..str.length()) |i| {
269	            switch (str.charAt(i)) {
270	                ';', '#', '\n', '\r' => break :needs_quotes true,
271	                else => {},
272	            }
273	        }
274	        break :needs_quotes false;
275	    };
276	
277	    if (needs_quotes) {
278	        builder.append(.lchar, '"');
279	        for (0..str.length()) |i| {
280	            const c = str.charAt(i);
281	            switch (c) {
282	                '"' => builder.append(.latin1, "\\\""),
283	                '\\' => builder.append(.latin1, "\\\\"),
284	                '\n' => builder.append(.latin1, "\\n"),
285	                '\r' => builder.append(.latin1, "\\r"),
286	                else => builder.append(.uchar, c),
287	            }
288	        }
289	        builder.append(.lchar, '"');
290	    } else {
291	        builder.append(.string, str);
292	    }
293	}
