// Bun.INI — INI format parser and stringifier
//
// Supports:
//  - Comment lines: `;...` and `#...` (after optional whitespace)
//  - Sections: `[name]` — represented as nested objects
//  - Key-value pairs: `key = value` or `key: value` (whitespace is trimmed)
//  - Inline comments: `key = value ; comment` (stripped outside of quotes)
//  - Quoted values: `key = "value"` or `key = 'value'`
//
// All values are returned as strings.

pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
    const object = JSValue.createEmptyObject(globalThis, 2);
    object.put(
        globalThis,
        ZigString.static("parse"),
        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}),
    );
    object.put(
        globalThis,
        ZigString.static("stringify"),
        jsc.JSFunction.create(globalThis, "stringify", stringify, 1, .{}),
    );
    return object;
}

/// Parse an INI-formatted string into a JavaScript object.
/// Sections become nested objects. All values are returned as strings.
pub fn parse(global: *jsc.JSGlobalObject, callFrame: *jsc.CallFrame) bun.JSError!jsc.JSValue {
    const input_value = callFrame.argument(0);

    if (input_value.isEmptyOrUndefinedOrNull()) {
        return global.throwInvalidArguments("Expected a string to parse", .{});
    }

    var input_slice = try input_value.toSlice(global, bun.default_allocator);
    defer input_slice.deinit();
    const input = input_slice.slice();

    const root_obj = JSValue.createEmptyObject(global, 4);
    var current_section: JSValue = root_obj;

    var pos: usize = 0;
    while (pos < input.len) {
        // Find end of line (\n or end-of-input)
        const line_start = pos;
        while (pos < input.len and input[pos] != '\n') : (pos += 1) {}
        const raw_line = input[line_start..pos];
        if (pos < input.len) pos += 1; // consume '\n'

        // Trim CR and surrounding spaces/tabs
        const line = std.mem.trim(u8, raw_line, " \t\r");

        // Skip empty lines and comment lines
        if (line.len == 0) continue;
        if (line[0] == ';' or line[0] == '#') continue;

        // Section header: [section_name]
        if (line[0] == '[') {
            const end_bracket = std.mem.indexOfScalar(u8, line, ']') orelse continue;
            const section_name = std.mem.trim(u8, line[1..end_bracket], " \t");
            if (section_name.len == 0) continue;

            const section_obj = JSValue.createEmptyObject(global, 4);
            var key_str = bun.String.borrowUTF8(section_name);
            defer key_str.deref();
            try root_obj.putMayBeIndex(global, &key_str, section_obj);
            current_section = section_obj;
            continue;
        }

        // Key = value  (also handle "key: value")
        const sep_pos = std.mem.indexOfAny(u8, line, "=:") orelse continue;
        const key = std.mem.trim(u8, line[0..sep_pos], " \t");
        if (key.len == 0) continue;

        var value_raw = line[sep_pos + 1 ..];

        // Strip inline comments that appear outside of quoted strings
        {
            var in_quote: ?u8 = null;
            var j: usize = 0;
            while (j < value_raw.len) : (j += 1) {
                const c = value_raw[j];
                if (in_quote) |q| {
                    if (c == q) in_quote = null;
                } else switch (c) {
                    '"', '\'' => in_quote = c,
                    ';', '#' => {
                        value_raw = value_raw[0..j];
                        break;
                    },
                    else => {},
                }
            }
        }

        const value_trimmed = std.mem.trim(u8, value_raw, " \t");

        // Unquote value if it is wrapped in matching quote characters
        const value = if (value_trimmed.len >= 2 and
            (value_trimmed[0] == '"' or value_trimmed[0] == '\'') and
            value_trimmed[value_trimmed.len - 1] == value_trimmed[0])
            value_trimmed[1 .. value_trimmed.len - 1]
        else
            value_trimmed;

        var key_bun = bun.String.borrowUTF8(key);
        defer key_bun.deref();
        const js_value = try bun.String.createUTF8ForJS(global, value);
        try current_section.putMayBeIndex(global, &key_bun, js_value);
    }

    return root_obj;
}

/// Stringify a JavaScript object into INI format.
/// Top-level scalar properties become bare `key = value` lines.
/// Top-level object properties become INI sections: `[name]\nkey = value\n...`
/// Arrays are serialized as comma-separated values.
pub fn stringify(global: *jsc.JSGlobalObject, callFrame: *jsc.CallFrame) bun.JSError!jsc.JSValue {
    const value = callFrame.argument(0);

    if (value.isEmptyOrUndefinedOrNull() or !value.isObject()) {
        return global.throwInvalidArguments("Expected an object to stringify", .{});
    }

    var builder: wtf.StringBuilder = .init();
    defer builder.deinit();

    var anything_written = false;

    // First pass: write top-level scalar (non-section) properties
    {
        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            global,
            try value.toObject(global),
        );
        defer iter.deinit();

        while (try iter.next()) |prop_name| {
            const prop_value = iter.value;
            if (prop_value.isUndefined() or prop_value.isSymbol() or prop_value.isFunction()) continue;
            // Skip plain objects — they become sections in the second pass
            if (prop_value.isObject() and !prop_value.isArray()) continue;

            builder.append(.string, prop_name);
            builder.append(.latin1, " = ");
            try appendINIValue(&builder, global, prop_value);
            builder.append(.lchar, '\n');
            anything_written = true;
        }
    }

    // Second pass: write top-level object properties as INI sections
    {
        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            global,
            try value.toObject(global),
        );
        defer iter.deinit();

        while (try iter.next()) |prop_name| {
            const prop_value = iter.value;
            if (prop_value.isUndefined() or prop_value.isSymbol() or prop_value.isFunction()) continue;
            if (!prop_value.isObject() or prop_value.isArray()) continue;

            // Blank line before each section when something precedes it
            if (anything_written) builder.append(.lchar, '\n');

            builder.append(.lchar, '[');
            builder.append(.string, prop_name);
            builder.append(.latin1, "]\n");

            var sec_iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
                global,
                try prop_value.toObject(global),
            );
            defer sec_iter.deinit();

            while (try sec_iter.next()) |sec_key| {
                const sec_value = sec_iter.value;
                if (sec_value.isUndefined() or sec_value.isSymbol() or sec_value.isFunction()) continue;

                builder.append(.string, sec_key);
                builder.append(.latin1, " = ");
                try appendINIValue(&builder, global, sec_value);
                builder.append(.lchar, '\n');
            }

            anything_written = true;
        }
    }

    return builder.toString(global);
}

fn appendINIValue(builder: *wtf.StringBuilder, global: *jsc.JSGlobalObject, value: JSValue) bun.JSError!void {
    const unwrapped = try value.unwrapBoxedPrimitive(global);

    if (unwrapped.isNull()) {
        builder.append(.latin1, "null");
        return;
    }

    if (unwrapped.isBoolean()) {
        builder.append(.latin1, if (unwrapped.asBoolean()) "true" else "false");
        return;
    }

    if (unwrapped.isInt32()) {
        builder.append(.int, unwrapped.asInt32());
        return;
    }

    if (unwrapped.isNumber()) {
        builder.append(.double, unwrapped.asNumber());
        return;
    }

    if (unwrapped.isArray()) {
        // Serialize arrays as comma-separated values
        var iter = try unwrapped.arrayIterator(global);
        var first = true;
        while (try iter.next()) |item| {
            if (!first) builder.append(.latin1, ", ");
            first = false;
            if (item.isNull() or item.isUndefined()) {
                // write nothing for null/undefined array elements
            } else if (item.isBoolean()) {
                builder.append(.latin1, if (item.asBoolean()) "true" else "false");
            } else if (item.isInt32()) {
                builder.append(.int, item.asInt32());
            } else if (item.isNumber()) {
                builder.append(.double, item.asNumber());
            } else {
                const item_str = try item.toBunString(global);
                defer item_str.deref();
                appendINIStringValue(builder, item_str);
            }
        }
        return;
    }

    if (unwrapped.isString()) {
        const str = try unwrapped.toBunString(global);
        defer str.deref();
        appendINIStringValue(builder, str);
        return;
    }

    // Fallback: convert to string representation
    const str = try unwrapped.toBunString(global);
    defer str.deref();
    appendINIStringValue(builder, str);
}

/// Write an INI string value, quoting it if it contains characters that
/// would be misinterpreted (comment markers, newlines, leading/trailing whitespace).
fn appendINIStringValue(builder: *wtf.StringBuilder, str: bun.String) void {
    const needs_quotes = needs_quotes: {
        if (str.length() == 0) break :needs_quotes false;
        const first = str.charAt(0);
        const last = str.charAt(str.length() - 1);
        // Leading or trailing whitespace must be quoted to survive a round-trip
        if (first == ' ' or first == '\t' or last == ' ' or last == '\t') break :needs_quotes true;
        // Inline-comment markers and newlines require quoting
        for (0..str.length()) |i| {
            switch (str.charAt(i)) {
                ';', '#', '\n', '\r' => break :needs_quotes true,
                else => {},
            }
        }
        break :needs_quotes false;
    };

    if (needs_quotes) {
        builder.append(.lchar, '"');
        for (0..str.length()) |i| {
            const c = str.charAt(i);
            switch (c) {
                '"' => builder.append(.latin1, "\\\""),
                '\\' => builder.append(.latin1, "\\\\"),
                '\n' => builder.append(.latin1, "\\n"),
                '\r' => builder.append(.latin1, "\\r"),
                else => builder.append(.uchar, c),
            }
        }
        builder.append(.lchar, '"');
    } else {
        builder.append(.string, str);
    }
}

